import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import Webcam from "react-webcam";
import axios from '../api/axios';

const StudyRoom = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const webcamRef = useRef(null);

    // 1. Timer State (Set to 1500 for 25 minutes, or 10 for testing)
    const [seconds, setSeconds] = useState(10); 
    const [isActive, setIsActive] = useState(false);

    // 2. Timer Logic & Auto-Redirect
    useEffect(() => {
        let interval = null;
        if (isActive && seconds > 0) {
            interval = setInterval(() => {
                setSeconds((prev) => prev - 1);
            }, 1000);
        } else if (seconds === 0) {
            clearInterval(interval);
            handleAutoFinish();
        }
        return () => clearInterval(interval);
    }, [isActive, seconds]);

    // 3. Finish Logic
    const handleAutoFinish = async () => {
        try {
            // Updates status to completed in the database
            await axios.patch(`/tasks/${id}`, { status: 'completed' });
            // Redirects to plan page for the next session
            navigate('/planPage');
        } catch (error) {
            console.error("Redirection failed:", error);
            navigate('/planPage'); // Redirect anyway so user isn't stuck
        }
    };

    const formatTime = (secs) => {
        const mins = Math.floor(secs / 60);
        const s = secs % 60;
        return `${mins}:${s < 10 ? '0' : ''}${s}`;
    };

    return (
        <div style={{ textAlign: 'center', padding: '50px', fontFamily: 'Arial' }}>
            <h2>Session Monitoring Active</h2>
            
            {/* Camera Access */}
            <div style={{ width: '400px', margin: '0 auto', borderRadius: '15px', overflow: 'hidden', border: '4px solid #2c3e50' }}>
                <Webcam 
                    audio={false} 
                    ref={webcamRef} 
                    screenshotFormat="image/jpeg" 
                    width="100%" 
                    onUserMediaError={() => alert("Please enable camera permissions!")}
                />
            </div>

            {/* Timer Display */}
            <h1 style={{ fontSize: '6rem', margin: '20px 0' }}>{formatTime(seconds)}</h1>

            {/* Control Button */}
            <button 
                onClick={() => setIsActive(!isActive)}
                style={{
                    padding: '15px 50px',
                    fontSize: '1.2rem',
                    backgroundColor: isActive ? '#e74c3c' : '#27ae60',
                    color: 'white',
                    border: 'none',
                    borderRadius: '5px',
                    cursor: 'pointer'
                }}
            >
                {isActive ? 'Pause Timer' : 'Start Study Session'}
            </button>

            <p style={{ marginTop: '20px', color: '#7f8c8d' }}>
                Once the timer hits 0:00, you will be automatically redirected to your plan.
            </p>
        </div>
    );
};

export default StudyRoom;
